import { SectionWrapper } from './SectionWrapper';

type ExperienceItem = {
  company: string;
  role: string;
  duration: string;
  achievements: string[];
};

const experience: ExperienceItem[] = [
  {
    company: 'Tech Company A',
    role: 'Backend Developer',
    duration: '2023 — Present',
    achievements: [
      'Designed and implemented REST APIs used by multiple product teams.',
      'Improved request latency and reliability by optimizing database queries and caching.',
      'Collaborated with frontend and DevOps teams to deliver features end-to-end.'
    ]
  },
  {
    company: 'Company B',
    role: 'Software Developer',
    duration: '2021 — 2023',
    achievements: [
      'Built internal tools that automated manual workflows and reporting.',
      'Contributed to refactoring legacy services into cleaner, modular components.',
      'Helped introduce better monitoring and logging across services.'
    ]
  }
];

export function Experience() {
  return (
    <SectionWrapper
      id="experience"
      title="Experience"
      subtitle="Timeline of roles and responsibilities."
    >
      <ol className="relative space-y-8 border-l border-slate-800 pl-6">
        {experience.map((item) => (
          <li key={`${item.company}-${item.role}`} className="space-y-2">
            <div className="absolute -left-[9px] mt-1 h-4 w-4 rounded-full border border-accent bg-slate-950" />
            <p className="text-xs font-medium uppercase tracking-[0.2em] text-slate-400">
              {item.duration}
            </p>
            <h3 className="text-sm font-semibold text-slate-100 sm:text-base">
              {item.role} · <span className="text-slate-300">{item.company}</span>
            </h3>
            <ul className="mt-1 list-disc space-y-1 pl-4 text-sm text-slate-300">
              {item.achievements.map((achievement) => (
                <li key={achievement}>{achievement}</li>
              ))}
            </ul>
          </li>
        ))}
      </ol>
    </SectionWrapper>
  );
}

